104					service.getValidToken({ installation: expiredInstallation }),
105				).rejects.toThrow('token refresh failed');
106	
107				expect(mockInstallationModel.markNeedsReauth).toHaveBeenCalledWith({
108					id: expiredInstallation._id,
109				});
110			});
