131					data: { values: [], isLast: false },
132				});
133	
134				const projects = await service.listProjects({ cloudId: 'cloud-1', token: 'tok' });
135	
136				expect(projects).toHaveLength(0);
137				expect(mockHttp.axiosRef.get).toHaveBeenCalledTimes(1);
138			});
139		});
